import React, { useCallback, useEffect, useMemo, useState } from 'react'
import { showToast } from '../../utils/toast'
import { useAuth } from '../../context/AuthContext'
import { taskService, productService } from '../../services/api'
import PondChartCard from '../../components/charts/PondChartCard' // Đồng bộ biểu đồ từ trang mùa vụ
import '../../styles/technician/technician-tasks.css'

const STATUS_OPTIONS = [
  { value: 'ALL', label: 'Tất cả trạng thái công việc' },
  { value: 'PENDING', label: 'Chờ xử lý' },
  { value: 'IN_PROGRESS', label: 'Đang thực hiện' },
  { value: 'COMPLETED', label: 'Hoàn thành' },
  { value: 'CANCELLED', label: 'Đã hủy' },
  { value: 'OVERDUE', label: 'Quá hạn' },
]

const TASK_TYPE_OPTIONS = [
  { value: '1', label: 'Xử lý ao (POND_PROCESS)' },
  { value: '2', label: 'Cho ăn (FEEDING)' },
  { value: '3', label: 'Cho thuốc (TREATMENT)' },
  { value: '4', label: 'Kiểm tra môi trường (ENVIRONMENTAL_CHECK)' },
  { value: '5', label: 'Thu hoạch (HARVEST)' },
  { value: '6', label: 'Công việc khác (OTHER)' },
]

const normalize = (v) => String(v || '').trim().toUpperCase()
const formatDate = (v) => (v ? new Date(v).toLocaleString('vi-VN') : '-')

const TechnicianTasks = () => {
  const { user } = useAuth()

  // ===== DATA STATE =====
  const [tasks, setTasks] = useState([])
  const [products, setProducts] = useState([])
  const [workers, setWorkers] = useState([])
  const [ponds, setPonds] = useState([])
  const [matrixPonds, setMatrixPonds] = useState([]) // State riêng cho ma trận ao nuôi khi tạo mới

  // ===== FILTER STATE =====
  const [filterStatus, setFilterStatus] = useState('')
  const [filterType, setFilterType] = useState('')
  const [filterPond, setFilterPond] = useState('')
  const [filterSeason, setFilterSeason] = useState('')
  const [filterWorker, setFilterWorker] = useState('')

  // ===== UI STATE =====
  const [loading, setLoading] = useState(false)
  const [loadingPonds, setLoadingPonds] = useState(false)
  const [isCreateOpen, setIsCreateOpen] = useState(false)
  const [isDetailOpen, setIsDetailOpen] = useState(false)
  const [selectedTask, setSelectedTask] = useState(null)

  // ===== FORM STATE =====
  const [form, setForm] = useState({
    task_type: '',
    description: '',
    start_date: '',
    due_date: '',
    product_id: '',
    quantity: '',
    assignments: []
  })

  // Hàm tính trạng thái động (Bao gồm check Quá hạn)
  const getComputedStatus = (task) => {
    const st = normalize(task.status)
    if (st === 'COMPLETED' || st === 'CANCELLED') return st
    if (task.due_date && new Date(task.due_date) < new Date()) {
      return 'OVERDUE'
    }
    return st
  }

  // ===== FETCH API ACTIONS =====
  const fetchTasks = useCallback(async () => {
    try {
      const res = await taskService.getAllTasks()
      setTasks(res?.data?.data || [])
    } catch (err) {
      console.error(err)
      showToast({ title: 'Không thể tải danh sách công việc', type: 'error' })
    }
  }, [])

  const fetchProducts = useCallback(async () => {
    try {
      const res = await productService.getAllProducts()
      setProducts(res?.data?.data || [])
    } catch (err) {
      console.error(err)
    }
  }, [])

  const fetchWorkersStatus = useCallback(async () => {
    try {
      const res = await taskService.getWorkersStatus()
      setWorkers(res?.data?.data || [])
    } catch (err) {
      console.error(err)
    }
  }, [])

  useEffect(() => {
    const loadInitialData = async () => {
      setLoading(true)
      try {
        await Promise.all([fetchTasks(), fetchProducts(), fetchWorkersStatus()])
        // Lấy danh sách toàn bộ ao ban đầu đổ vào bộ lọc ngoài thanh công cụ
        const pondRes = await taskService.getPondsByType('OTHER')
        setPonds(pondRes?.data?.data || [])
      } catch (err) {
        console.error(err)
      } finally {
        setLoading(false)
      }
    }
    loadInitialData()
  }, [fetchTasks, fetchProducts, fetchWorkersStatus])

  // ===== DỰ TOÁN THỐNG KÊ TOÀN CỤC (Đồng bộ thiết kế trang Season) =====
  const stats = useMemo(() => {
    let total = tasks.length
    let pending = 0
    let inProgress = 0
    let completed = 0
    let overdue = 0

    tasks.forEach(t => {
      const status = getComputedStatus(t)
      if (status === 'PENDING') pending++
      else if (status === 'IN_PROGRESS') inProgress++
      else if (status === 'COMPLETED') completed++
      else if (status === 'OVERDUE') overdue++
    })

    return { total, pending, inProgress, completed, overdue }
  }, [tasks])

  // Cấu trúc dữ liệu Chart (Khớp với component PondChartCard)
  const chartData = useMemo(() => {
    return [
      { name: 'Chờ xử lý', 'Số công việc': stats.pending },
      { name: 'Đang làm', 'Số công việc': stats.inProgress },
      { name: 'Hoàn thành', 'Số công việc': stats.completed },
      { name: 'Quá hạn', 'Số công việc': stats.overdue },
    ]
  }, [stats])

  // ===== LỌC TỰ ĐỘNG DANH SÁCH MÙA VỤ ĐỘNG TỪ TASKS =====
  const seasonsOptions = useMemo(() => {
    const map = new Map()
    tasks.forEach(t => {
      if (t.season_id && t.season_name) {
        map.set(String(t.season_id), t.season_name)
      }
    })
    return Array.from(map.entries()).map(([id, name]) => ({ id, name }))
  }, [tasks])

  // ===== CHUẨN HÓA LOGIC 5 LIST LỌC =====
  const filteredTasks = useMemo(() => {
    return tasks.filter(task => {
      const matchType = !filterType || String(task.type_id) === String(filterType)
      const matchPond = !filterPond || String(task.pond_id) === String(filterPond)
      const matchSeason = !filterSeason || String(task.season_id) === String(filterSeason)
      const matchWorker = !filterWorker || (
        task.assigned_workers_list && 
        task.assigned_workers_list.some(w => String(w.worker_id) === String(filterWorker))
      )
      const matchStatus = !filterStatus || String(getComputedStatus(task)) === String(filterStatus)

      return matchType && matchPond && matchSeason && matchWorker && matchStatus
    })
  }, [tasks, filterType, filterPond, filterSeason, filterWorker, filterStatus])

  // ===== ACTION XỬ LÝ SỰ KIỆN FORM TẠO =====
  const handleTypeChange = async (e) => {
    const typeCode = e.target.value ? e.target.value.trim().toUpperCase() : ''
    setForm(prev => ({
      ...prev,
      task_type: typeCode,
      assignments: [],
      product_id: '',
      quantity: ''
    }))
    setMatrixPonds([])

    if (!typeCode) return
    setLoadingPonds(true)
    try {
      const res = await taskService.getPondsByType(typeCode)
      setMatrixPonds(res?.data?.data || [])
    } catch (err) {
      console.error(err)
      showToast({ title: 'Lỗi nạp ma trận ao nuôi', type: 'error' })
    } finally {
      setLoadingPonds(false)
    }
  }

  const toggleAssignment = (workerId, pondId) => {
    const wId = Number(workerId)
    const pId = Number(pondId)

    setForm(prev => {
      const exists = prev.assignments.some(a => a.worker_id === wId && a.pond_id === pId)
      let nextAssignments = []
      if (exists) {
        nextAssignments = prev.assignments.filter(a => !(a.worker_id === wId && a.pond_id === pId))
      } else {
        nextAssignments = [...prev.assignments, { worker_id: wId, pond_id: pId }]
      }
      return { ...prev, assignments: nextAssignments }
    })
  }

  const handleCreateTask = async () => {
    try {
      const payload = {
        task_type: form.task_type,
        description: form.description,
        start_date: form.start_date,
        due_date: form.due_date,
        product_id: form.product_id ? Number(form.product_id) : null,
        quantity: form.quantity ? Number(form.quantity) : null,
        assignments: form.assignments
      }

      await taskService.createTask(payload)
      showToast({ title: 'Phân công chuỗi công việc thành công!', type: 'success' })
      setIsCreateOpen(false)
      fetchTasks()
      fetchWorkersStatus()
    } catch (err) {
      showToast({ title: err.response?.data?.message || 'Lỗi khi tạo công việc', type: 'error' })
    }
  }

  const handleCompleteTask = async (taskId) => {
    if (!window.confirm('Xác nhận hoàn thành công việc này và cập nhật kho vật tư tương ứng?')) return
    try {
      await taskService.completeTask(taskId)
      showToast({ title: 'Đã hoàn thành và hạch toán kho vật tư thành công!', type: 'success' })
      if (selectedTask) setIsDetailOpen(false)
      fetchTasks()
    } catch (err) {
      showToast({ title: err.response?.data?.message || 'Thao tác thất bại', type: 'error' })
    }
  }

  const handleCancelTask = async (taskId) => {
    if (!window.confirm('Bạn có chắc chắn muốn hủy công việc đang chờ này không?')) return
    try {
      await taskService.cancelTask(taskId)
      showToast({ title: 'Đã hủy bỏ công việc thành công!', type: 'success' })
      if (selectedTask) setIsDetailOpen(false)
      fetchTasks()
    } catch (err) {
      showToast({ title: err.response?.data?.message || 'Không thể hủy bỏ', type: 'error' })
    }
  }

  return (
    <div className="technician-tasks_page text-sans">
      
      {/* KHỐI 1: TIÊU ĐỀ TRANG CHÍNH */}
      <div className="flex-row-center-space margin-bottom-20">
        <div>
          <h2 className="admin-users_title" style={{ margin: 0 }}>Giám sát & Phân công công việc</h2>
          <p style={{ color: '#64748b', margin: '4px 0 0', fontSize: '14px' }}>
            Quản lý ma trận phân công công việc chi tiết cho các kỹ thuật viên ao nuôi.
          </p>
        </div>
        <button className="btn btn-primary" onClick={() => setIsCreateOpen(true)}>
          + Giao việc & Phân công mới
        </button>
      </div>

      {/* KHỐI 2: THẺ TỔNG QUAN STATS CARDS (Đồng bộ với Mùa Vụ) */}
      <div className="technician-tasks_stats-grid">
        <div className="technician-tasks_stat-card">
          <span className="technician-tasks_stat-label">Tổng số công việc</span>
          <span className="technician-tasks_stat-value">{stats.total}</span>
        </div>
        <div className="technician-tasks_stat-card" style={{ borderLeft: '4px solid #f59e0b' }}>
          <span className="technician-tasks_stat-label">Chờ xử lý</span>
          <span className="technician-tasks_stat-value" style={{ color: '#f59e0b' }}>{stats.pending}</span>
        </div>
        <div className="technician-tasks_stat-card" style={{ borderLeft: '4px solid #3b82f6' }}>
          <span className="technician-tasks_stat-label">Đang thực hiện</span>
          <span className="technician-tasks_stat-value" style={{ color: '#3b82f6' }}>{stats.inProgress}</span>
        </div>
        <div className="technician-tasks_stat-card" style={{ borderLeft: '4px solid #10b981' }}>
          <span className="technician-tasks_stat-label">Đã hoàn thành</span>
          <span className="technician-tasks_stat-value" style={{ color: '#10b981' }}>{stats.completed}</span>
        </div>
        <div className="technician-tasks_stat-card" style={{ borderLeft: '4px solid #ef4444' }}>
          <span className="technician-tasks_stat-label">Việc quá hạn</span>
          <span className="technician-tasks_stat-value" style={{ color: '#ef4444' }}>{stats.overdue}</span>
        </div>
      </div>

      {/* KHỐI 3: BIỂU ĐỒ TRỰC QUAN (Đồng bộ thiết kế đồ thị) */}
      <div className="technician-tasks_charts-grid">
        <div className="technician-tasks_chart-card">
          <h3 className="technician-tasks_chart-title">Thống kê phân bổ trạng thái nhiệm vụ kỹ sư</h3>
          <PondChartCard 
            title="Tỉ lệ phân bổ nhiệm vụ thực tế"
            data={chartData}
            dataKey="Số công việc"
          />
        </div>
      </div>

      {/* KHỐI 4: THANH TIỆN ÍCH LỌC (5 BỘ LỌC ĐÃ ĐỒNG BỘ) */}
      <div className="tasks-filter-wrapper">
        <div className="grid-col-5 gap-12">
          
          {/* 1. Lọc theo Loại công việc */}
          <div>
            <label className="admin-users_detail-label">Loại công việc</label>
            <select className="form-select-base" value={filterType} onChange={e => setFilterType(e.target.value)}>
              <option value="">Tất cả loại công việc</option>
              {TASK_TYPE_OPTIONS.map(opt => (
                <option key={opt.value} value={opt.value}>{opt.label}</option>
              ))}
            </select>
          </div>

          {/* 2. Lọc theo Ao nuôi */}
          <div>
            <label className="admin-users_detail-label">Ao nuôi quản lý</label>
            <select className="form-select-base" value={filterPond} onChange={e => setFilterPond(e.target.value)}>
              <option value="">Tất cả ao nuôi</option>
              {ponds.map(p => (
                <option key={p.pond_id} value={p.pond_id}>{p.pond_name} ({p.pond_code})</option>
              ))}
            </select>
          </div>

          {/* 3. Lọc theo Mùa vụ */}
          <div>
            <label className="admin-users_detail-label">Mùa vụ nuôi</label>
            <select className="form-select-base" value={filterSeason} onChange={e => setFilterSeason(e.target.value)}>
              <option value="">Tất cả mùa vụ</option>
              {seasonsOptions.map(s => (
                <option key={s.id} value={s.id}>{s.name}</option>
              ))}
            </select>
          </div>

          {/* 4. Lọc theo Nhân viên */}
          <div>
            <label className="admin-users_detail-label">Nhân viên đảm nhận</label>
            <select className="form-select-base" value={filterWorker} onChange={e => setFilterWorker(e.target.value)}>
              <option value="">Tất cả nhân viên</option>
              {workers.map(w => (
                <option key={w.user_id} value={w.user_id}>{w.full_name} ({w.username})</option>
              ))}
            </select>
          </div>

          {/* 5. Lọc theo Trạng thái */}
          <div>
            <label className="admin-users_detail-label">Trạng thái xử lý</label>
            <select className="form-select-base" value={filterStatus} onChange={e => setFilterStatus(e.target.value)}>
              <option value="">Tất cả trạng thái</option>
              {STATUS_OPTIONS.filter(o => o.value !== 'ALL').map(opt => (
                <option key={opt.value} value={opt.value}>{opt.label}</option>
              ))}
            </select>
          </div>

        </div>
      </div>

      {/* KHỐI 5: BẢNG DỮ LIỆU CHÍNH */}
      {loading ? (
        <div className="text-center padding-top-24">Đang tải dữ liệu vận hành...</div>
      ) : (
        <div className="table-responsive-wrapper">
          <table className="table-base">
            <thead>
              <tr>
                <th>Mã việc</th>
                <th>Loại nhiệm vụ</th>
                <th>Ao nuôi</th>
                <th>Mùa vụ</th>
                <th>Nhân sự thực hiện</th>
                <th>Hạn hoàn thành</th>
                <th>Trạng thái</th>
                <th style={{ textAlign: 'center' }}>Thao tác</th>
              </tr>
            </thead>
            <tbody>
              {filteredTasks.length === 0 ? (
                <tr>
                  <td colSpan="8" style={{ textAlign: 'center', color: '#94a3b8', padding: '24px' }}>
                    Không tìm thấy công việc nào thỏa mãn điều kiện lọc.
                  </td>
                </tr>
              ) : (
                filteredTasks.map((task) => {
                  const computedSt = getComputedStatus(task)
                  let badgeClass = 'task-status--pending'
                  let label = 'Chờ xử lý'

                  if (computedSt === 'IN_PROGRESS') { badgeClass = 'task-status--progress'; label = 'Đang thực hiện'; }
                  else if (computedSt === 'COMPLETED') { badgeClass = 'task-status--done'; label = 'Hoàn thành'; }
                  else if (computedSt === 'CANCELLED') { badgeClass = 'task-status--cancelled'; label = 'Đã hủy'; }
                  else if (computedSt === 'OVERDUE') { badgeClass = 'task-status--overdue'; label = 'Quá hạn'; }

                  return (
                    <tr key={task.task_id} className="table-tr-hover">
                      <td><strong>#{task.task_id}</strong></td>
                      <td>
                        <span className="font-weight-600">{task.type_name || 'Công việc khác'}</span>
                        {task.description && <div className="task-row-desc text-truncate-1">{task.description}</div>}
                      </td>
                      <td>{task.pond_name || <span className="text-muted">-</span>}</td>
                      <td>{task.season_name || <span className="text-muted">Không thuộc mùa vụ</span>}</td>
                      <td>
                        <div className="worker-info-cell">
                          <span>
                            {task.assigned_workers_list?.map(w => w.full_name).join(', ') || 'Chưa phân công'}
                          </span>
                        </div>
                      </td>
                      <td>{formatDate(task.due_date)}</td>
                      <td>
                        <span className={`task-status ${badgeClass}`}>{label}</span>
                      </td>
                      <td style={{ textAlign: 'center' }}>
                        <button 
                          className="btn btn-secondary btn-sm"
                          onClick={() => { setSelectedTask(task); setIsDetailOpen(true); }}
                        >
                          Chi tiết
                        </button>
                      </td>
                    </tr>
                  )
                })
              )}
            </tbody>
          </table>
        </div>
      )}

      {/* ===== CÁC MODAL CHI TIẾT & TẠO MỚI (GIỮ NGUYÊN HOẠT ĐỘNG NHƯ CŨ) ===== */}
      {/* (Phần code hiển thị Modal Tạo Mới Ma Trận và Modal Chi Tiết được giữ nguyên vẹn từ file gốc của bạn) */}
      {isCreateOpen && (
        <div className="admin-users_modal-overlay">
          <div className="admin-users_modal-box" style={{ maxWidth: '900px', width: '90%' }}>
            <h3 className="admin-users_modal-title">Giao việc & Phân công chuỗi mục tiêu</h3>
            <div className="admin-users_form-grid">
              
              <div>
                <label className="admin-users_detail-label">Chọn danh mục công việc <span className="text-red">*</span></label>
                <select className="form-select-base" value={form.task_type} onChange={handleTypeChange}>
                  <option value="">-- Chọn Loại việc --</option>
                  {TASK_TYPE_OPTIONS.map(opt => (
                    <option key={opt.value} value={opt.label.split('(')[1].replace(')', '')}>{opt.label}</option>
                  ))}
                </select>
              </div>

              <div style={{ gridColumn: '1 / -1' }}>
                <label className="admin-users_detail-label">Mô tả/Chỉ dẫn chi tiết công việc</label>
                <textarea 
                  className="form-textarea-base" 
                  rows="2"
                  value={form.description}
                  onChange={(e) => setForm({ ...form, description: e.target.value })}
                  placeholder="Nhập ghi chú hướng dẫn kỹ thuật..."
                />
              </div>

              {/* MA TRẬN PHÂN CÔNG */}
              <div style={{ gridColumn: '1 / -1' }}>
                <label className="admin-users_detail-label margin-bottom-8" style={{ display: 'block' }}>
                  Ma trận phân công Nhân sự & Ao nuôi áp dụng {loadingPonds && <span className="text-muted">(Đang lọc ao...)</span>}
                </label>
                
                {form.task_type && matrixPonds.length === 0 && !loadingPonds && (
                  <div className="alert-box-warning">Không tìm thấy ao nuôi nào ở trạng thái phù hợp cho loại việc này.</div>
                )}

                {matrixPonds.length > 0 && (
                  <div className="table-responsive-wrapper" style={{ maxHeight: '250px', overflowY: 'auto' }}>
                    <table className="matrix-table-base">
                      <thead>
                        <tr>
                          <th className="matrix-th-worker" style={{ textAlign: 'left' }}>Nhân công / Ao nuôi</th>
                          {matrixPonds.map(p => (
                            <th key={`head-pond-${p.pond_id}`} className="matrix-th-pond" style={{ textAlign: 'center' }}>
                              {p.pond_name}
                            </th>
                          ))}
                        </tr>
                      </thead>
                      <tbody>
                        {workers.map(w => {
                          const wId = Number(w.user_id)
                          const isBusy = normalize(w.status) === 'BUSY'
                          return (
                            <tr key={`row-worker-${w.user_id}`}>
                              <td style={{ fontWeight: '500' }}>
                                {w.full_name} 
                                <span className={`margin-left-8 ${isBusy ? 'text-red' : 'text-green'}`} style={{ fontSize: '12px' }}>
                                  ({isBusy ? 'Bận' : 'Rảnh'})
                                </span>
                              </td>
                              {matrixPonds.map(p => {
                                const pId = Number(p.pond_id)
                                const isChecked = form.assignments.some(a => a.worker_id === wId && a.pond_id === pId)
                                return (
                                  <td key={`cell-${wId}-${pId}`} style={{ textAlign: 'center' }}>
                                    <input 
                                      type="checkbox"
                                      checked={isChecked}
                                      disabled={isBusy && !isChecked}
                                      onChange={() => toggleAssignment(wId, pId)}
                                    />
                                  </td>
                                )
                              })}
                            </tr>
                          )
                        })}
                      </tbody>
                    </table>
                  </div>
                )}
              </div>

              {/* ĐIỀU PHỐI VẬT TƯ */}
              <div>
                <label className="admin-users_detail-label">Vật tư xuất kho đi kèm (Nếu có)</label>
                <select className="form-select-base" value={form.product_id} onChange={(e) => setForm({ ...form, product_id: e.target.value })}>
                  <option value="">-- Không sử dụng vật tư --</option>
                  {products.map(p => (
                    <option key={p.product_id} value={p.product_id}>{p.product_name} (Tồn: {p.stock_quantity} {p.unit})</option>
                  ))}
                </select>
              </div>

              <div>
                <label className="admin-users_detail-label">Số lượng định mức từng ao</label>
                <input 
                  type="number" 
                  className="form-input-text-base"
                  value={form.quantity}
                  disabled={!form.product_id}
                  onChange={(e) => setForm({ ...form, quantity: e.target.value })}
                  placeholder="VD: 5"
                />
              </div>

              {/* THỜI GIAN */}
              <div>
                <label className="admin-users_detail-label">Thời gian bắt đầu <span className="text-red">*</span></label>
                <input type="datetime-local" className="form-input-date-base" value={form.start_date} onChange={e => setForm({ ...form, start_date: e.target.value })} />
              </div>
              <div>
                <label className="admin-users_detail-label">Hạn chót hoàn thành <span className="text-red">*</span></label>
                <input type="datetime-local" className="form-input-date-base" value={form.due_date} onChange={e => setForm({ ...form, due_date: e.target.value })} />
              </div>

            </div>

            <div className="admin-users_modal-buttons admin-users_form-buttons margin-top-24">
              <button type="button" className="btn btn-secondary" onClick={() => setIsCreateOpen(false)}>Hủy bỏ</button>
              <button 
                type="button" 
                className="btn btn-primary" 
                onClick={handleCreateTask}
                disabled={form.assignments.length === 0 || !form.start_date || !form.due_date}
              >
                Xác nhận tạo {form.assignments.length} công việc
              </button>
            </div>
          </div>
        </div>
      )}

      {/* MODAL CHI TIẾT CÔNG VIỆC */}
      {isDetailOpen && selectedTask && (
        <div className="admin-users_modal-overlay">
          <div className="admin-users_modal-box" style={{ maxWidth: '600px', width: '90%' }}>
            <h3 className="admin-users_modal-title">Chi tiết lịch trình vận hành #{selectedTask.task_id}</h3>
            
            <div className="admin-users_detail-grid" style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
              <div style={{ background: '#f8fafc', padding: '10px', borderRadius: '8px' }}>
                <strong>Loại nhiệm vụ:</strong> <div>{selectedTask.type_name}</div>
              </div>
              <div style={{ background: '#f8fafc', padding: '10px', borderRadius: '8px' }}>
                <strong>Ao nuôi áp dụng:</strong> <div>{selectedTask.pond_name} ({selectedTask.pond_code})</div>
              </div>
              <div style={{ background: '#f8fafc', padding: '10px', borderRadius: '8px' }}>
                <strong>Mùa vụ hiện hành:</strong> <div>{selectedTask.season_name || 'Không thuộc vụ mùa'}</div>
              </div>
              <div style={{ background: '#f8fafc', padding: '10px', borderRadius: '8px' }}>
                <strong>Trạng thái hệ thống:</strong> <div>{getComputedStatus(selectedTask)}</div>
              </div>
              <div style={{ background: '#f8fafc', padding: '10px', borderRadius: '8px' }}>
                <strong>Ngày bắt đầu:</strong> <div>{formatDate(selectedTask.start_date)}</div>
              </div>
              <div style={{ background: '#f8fafc', padding: '10px', borderRadius: '8px' }}>
                <strong>Hạn hoàn thành:</strong> <div>{formatDate(selectedTask.due_date)}</div>
              </div>
              
              {selectedTask.product_usage?.product_name && (
                <div style={{ gridColumn: '1 / -1', background: '#f0fdf4', padding: '10px', borderRadius: '8px' }}>
                  <strong>Vật tư chỉ định tiêu hao:</strong> 
                  <div>{selectedTask.product_usage.product_name} - Số lượng: {selectedTask.product_usage.quantity} {selectedTask.product_usage.unit}</div>
                </div>
              )}

              <div style={{ gridColumn: '1 / -1', background: '#f8fafc', padding: '10px', borderRadius: '8px' }}>
                <strong>Chỉ dẫn chi tiết:</strong>
                <p style={{ margin: '4px 0 0', color: '#475569' }}>{selectedTask.description || '(Không có mô tả bổ sung)'}</p>
              </div>
            </div>

            <div className="admin-users_modal-buttons margin-top-24" style={{ display: 'flex', justifyContent: 'between', gap: '8px' }}>
              <div style={{ flexGrow: 1, display: 'flex', gap: '8px' }}>
                {getComputedStatus(selectedTask) === 'PENDING' && (
                  <button className="btn btn-danger" onClick={() => handleCancelTask(selectedTask.task_id)}>Hủy công việc</button>
                )}
                {['PENDING', 'IN_PROGRESS', 'OVERDUE'].includes(getComputedStatus(selectedTask)) && (
                  <button className="btn btn-primary" onClick={() => handleCompleteTask(selectedTask.task_id)}>Xác nhận hoàn thành</button>
                )}
              </div>
              <button className="btn btn-secondary" onClick={() => setIsDetailOpen(false)}>Đóng</button>
            </div>
          </div>
        </div>
      )}

    </div>
  )
}

export default TechnicianTasks
